// First AJAX request
// First AJAX request
jQuery.ajax({
    url: "/acciones/totalaccionesyactividades",
    type: 'GET',
    error: function() {
      // Manejar error si es necesario
    },
    dataType: 'json',
    success: function(data) {
      console.log(data);

      // Arrays para el gráfico
      var array_NAME_USER = [];
      var array_TOTAL_NOTIFICATIONS = [];

      // Iterar sobre los años en la respuesta
      for (var year in data) {
        if (data.hasOwnProperty(year)) {
          array_NAME_USER.push(year + " - Acciones"); // Etiquetas para el gráfico
          array_TOTAL_NOTIFICATIONS.push(data[year].Acciones);

          array_NAME_USER.push(year + " - Actividades"); // Etiquetas para el gráfico
          array_TOTAL_NOTIFICATIONS.push(data[year].Actividades);
        }
      }

      var ctx = document.getElementById('solicitudTipo').getContext('2d');
      var solicitudTipo = new Chart(ctx, {
        type: 'pie',
        data: {
          labels: array_NAME_USER,
          datasets: [{
            label: 'Totales por Año', // Etiqueta del gráfico más descriptiva
            data: array_TOTAL_NOTIFICATIONS,
            backgroundColor: generarColores(array_NAME_USER.length), // Función para generar colores
            borderColor: generarColores(array_NAME_USER.length),
            borderWidth: 1
          }]
        },
        options: {
          // Opciones adicionales si son necesarias
        }
      });
    }
  });

  // Función para generar colores pastel
  function generarColores(cantidad) {
    var coloresPastel = [
      'rgba(255, 192, 203, 1)', // Rosa pastel
      'rgba(173, 216, 230, 1)', // Azul pastel
      'rgba(255, 250, 205, 1)', // Amarillo pastel
      'rgba(144, 238, 144, 1)', // Verde pastel
      'rgba(255, 228, 196, 1)', // Naranja pastel
      'rgba(220, 220, 220, 1)', // Gris pastel
      'rgba(255, 160, 122, 1)', // Salmón pastel
      'rgba(230, 230, 250, 1)', // Lavanda pastel
      'rgba(240, 128, 128, 1)', // Rojo claro pastel
      'rgba(255, 215, 0, 1)',   // Oro pastel
       'rgba(160, 82, 45, 1)',  // Sienna pastel
       'rgba(210, 180, 140, 1)', // Tan pastel
       'rgba(176, 196, 222, 1)', // Azul acero pastel
       'rgba(224, 255, 255, 1)', // Azul cielo pastel
       'rgba(245, 222, 179, 1)', // Beige pastel
       'rgba(218, 112, 214, 1)'  // Orquídea pastel

    ];
    var colores = [];
    for (var i = 0; i < cantidad; i++) {
      colores.push(coloresPastel[i % coloresPastel.length]); // Usar el módulo para repetir colores si es necesario
    }
    return colores;
  }
  jQuery.ajax({
    url: "/acciones/totalaccionesyactividades",
    type: 'GET',
    dataType: 'json',
    success: function(data) {
        console.log(data);

        var labels = [];
        var datasets = [
            {
                label: 'Acciones',
                data: [],
                borderColor: 'rgba(255, 99, 132, 1)',
                fill: false
            },
            {
                label: 'Actividades',
                data: [],
                borderColor: 'rgba(54, 162, 235, 1)',
                fill: false
            }
        ];

        for (var year in data) {
            if (data.hasOwnProperty(year)) {
                labels.push(year);
                datasets[0].data.push(data[year].Acciones);
                datasets[1].data.push(data[year].Actividades);
            }
        }

        var ctx = document.getElementById('solicitudTipo2').getContext('2d');
        var solicitudTipo2 = new Chart(ctx, {
            type: 'line',
            data: {
                labels: labels,
                datasets: datasets
            },
            options: {
                scales: {
                    y: {
                        beginAtZero: true, // El eje Y comienza en 0 para mejor visualización
                        // Los valores -40, 0 y 20 no tienen sentido con la información que se provee, se ajusta a los datos
                        min: Math.min(...datasets[0].data, ...datasets[1].data) - 1, // Valor mínimo del eje Y, ajustado a los datos
                        max: Math.max(...datasets[0].data, ...datasets[1].data) + 1  // Valor máximo del eje Y, ajustado a los datos
                    }
                },
                plugins: {
                    annotation: {
                        annotations: [] // Se eliminan las líneas de anotación, no aportan valor con los datos actuales
                    }
                }
            }
        });
    },
    error: function(error) {
        console.error("Error al cargar los datos:", error);
        // Aquí puedes mostrar un mensaje de error en la página si lo deseas
    }
});
  jQuery.ajax({
    url: "/acciones/totalaccionesyactividades",
    type: 'GET',
    error: function() {
      // Manejar error si es necesario
    },
    dataType: 'json',
    success: function(data) {
      console.log(data);

      // Crear los arrays para el gráfico
      var array_YEARS = [];
      var array_TOTAL_ACCIONES2 = [];
      var array_TOTAL_ACTIVIDADES = [];

      // Iterar sobre los años en la respuesta
      for (var year in data) {
        if (data.hasOwnProperty(year)) {
          array_YEARS.push(year);
          array_TOTAL_ACCIONES2.push(data[year].Acciones);
          array_TOTAL_ACTIVIDADES.push(data[year].Actividades);
        }
      }

      var ctx = document.getElementById('solicitudTipo3').getContext('2d');
      var solicitudTipo = new Chart(ctx, {
        type: 'bar',
        data: {
          labels: array_YEARS,
          datasets: [{
            label: 'TOTAL_ACCIONES2',
            data: array_TOTAL_ACCIONES2,
            backgroundColor: 'rgba(255, 87, 51, 1)',
            borderColor: 'rgba(255, 87, 51, 1)',
            borderWidth: 1
          },
          {
            label: 'TOTAL_ACTIVIDADES',
            data: array_TOTAL_ACTIVIDADES,
            backgroundColor: 'rgba(52, 152, 219, 1)',
            borderColor: 'rgba(52, 152, 219, 1)',
            borderWidth: 1
          }]
        },
        options: {
            scales: {
                y: {
                    beginAtZero: true,
                    suggestedMax: 5, // Establece un límite superior sugerido para el eje Y (ajusta este valor según tus datos)
                    ticks: {
                        stepSize: 1,
                        callback: function(value, index, values) {
                            return Math.floor(value);
                        }
                    }
                }
            }
        }
      });
    },
  });
